var DoH = Enumerable.Range(8, 7);
var gearSets = GearsetManager.GearSets.Where(i => i.InUse && DoH.Contains((int)i.Class) && Core.Player.Levels[i.Class] > 69).ToList().OrderBy(y => Core.Player.Levels[y.Class]);
if (gearSets.Any())
{
  gearSets.First().Activate();
  await Coroutine.Sleep(2000);
}


        uint[] questNpcIds = { 1047120,1047109,1047135,1047132,1047097 };
        var npcId = GameObjectManager.GameObjects.Where(r => r.IsTargetable && questNpcIds.Contains(r.NpcId)).OrderBy(r => r.Distance()).FirstOrDefault();

        if (!npcId.IsWithinInteractRange)
        {
          var _target = npcId.Location;
          Navigator.PlayerMover.MoveTowards(_target);

          while (_target.Distance2D(Core.Me.Location) >= 4)
          {
            Navigator.PlayerMover.MoveTowards(_target);
            await Coroutine.Sleep(100);
          }

          Navigator.PlayerMover.MoveStop();
        }

        npcId.Interact();
				await Buddy.Coroutines.Coroutine.Wait(10000, () => LlamaLibrary.RemoteWindows.BankaCraftworksSupply.Instance.IsOpen || Talk.DialogOpen);

				if (Talk.DialogOpen)
					{
						while (Talk.DialogOpen)
						{
							Talk.Next();
							await Coroutine.Wait(1000, () => !Talk.DialogOpen);
							await Coroutine.Wait(1000, () => Talk.DialogOpen);
							await Coroutine.Yield();
						}
					}

				if (LlamaLibrary.RemoteWindows.BankaCraftworksSupply.Instance.IsOpen)
				{
            ff14bot.Helpers.Logging.WriteDiagnostic("Wachumeqimeqi: Starting HandOverItems");
						await LlamaLibrary.RemoteWindows.BankaCraftworksSupply.Instance.HandOverItems();
				}
